import { describe, it, expect } from "vitest";
import { processSteps } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote - base premiums", () => {
    it.todo("should return 5 G for an empty item list (processing fee only)");
    it.todo("should return base premium plus fee for a single sword (100 + 5 = 105 G)");
    it.todo("should return base premium plus fee for a single amulet (60 + 5 = 65 G)");
    it.todo("should return base premium plus fee for a single staff (80 + 5 = 85 G)");
    it.todo("should return base premium plus fee for a single potion (40 + 5 = 45 G)");
    it.todo("should return sum of base premiums plus fee for multiple different items");
  });

  describe("Quote - components", () => {
    it.todo("should return 25 G base premium per individual component (1 rune = 25 + 5 = 30 G)");
    it.todo("should return 50 G for 2 runes (no block, 2 x 25 + 5 = 55 G)");
    it.todo("should return 60 G for exactly 3 alike components (block discount, 60 + 5 = 65 G)");
    it.todo("should return 100 G for 4 runes (no block for 4, 4 x 25 + 5 = 105 G)");
    it.todo("should return 75 G for 2 runes and 1 moonstone (different types, no block, 3 x 25 + 5 = 80 G)");
    it.todo("should return 120 G for 3 runes and 3 moonstones (two separate blocks, 60 + 60 + 5 = 125 G)");
  });

  describe("Quote - item-level modifiers", () => {
    it.todo("should add 50% surcharge for a cursed item");
    it.todo("should add 30% surcharge for high enchantment (level >= 5)");
    it.todo("should apply both cursed and high enchantment surcharges to same item");
  });

  describe("Quote - policy-level modifiers", () => {
    it.todo("should add 10% first insurance surcharge (each item treated as first insurance)");
    it.todo("should apply -20% loyalty discount for long-standing customer (>= 2 years)");
    it.todo("should apply -15% follow-up discount for each contract after the first");
  });

  describe("Quote - rounding and integration", () => {
    it.todo("should round final premium up in MHPCO's favor");
    it.todo("should compute newcomer cursed sword as 165 G");
    it.todo("should compute long-standing customer second contract cursed sword enchantment 7 as 160 G");
  });

  describe("Claim - basic processing", () => {
    it.todo("should subtract 100 G deductible from damage amount");
    it.todo("should cap total payout at 2x insurance sum");
    it.todo("should return remaining cap after a claim");
  });

  describe("Claim - special reimbursement rules", () => {
    it.todo("should reimburse at 50% for enchantment >= 8");
    it.todo("should fully reimburse for dragon material");
    it.todo("should apply 50% when both dragon material and enchantment >= 8");
    it.todo("should fully reimburse for dragon material with enchantment < 8, then deductible");
  });

  describe("Error handling", () => {
    it.todo("should reject claim referencing an item not in the policy");
    it.todo("should reject negative damage amount");
    it.todo("should reject more damage entries of a type than policy covers");
  });
});

