const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const basePremium = (item: { type: string }): number =>
  BASE_PREMIUMS[item.type] ?? 0;

interface Customer {
  yearsWithMHPCO: number;
}

interface QuoteResult {
  premium: number;
}

const quotePremium = (items: Array<{ type: string }>): number =>
  items.reduce((sum, item) => sum + basePremium(item), 0) + PROCESSING_FEE;

export const processSteps = (customer: Customer, steps: Array<{ op: string; items: Array<{ type: string }> }>): Array<QuoteResult> =>
  steps.map((step) => ({
    premium: quotePremium(step.items),
  }));

