const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

interface Customer {
  yearsWithMHPCO: number;
}

interface QuoteResult {
  premium: number;
}

const BLOCK_SIZE = 3;
const BLOCK_PRICE = 60;

const quotePremium = (items: Array<{ type: string }>): number => {
  const counts: Record<string, number> = {};
  for (const item of items) {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
  }
  let total = 0;
  for (const [type, count] of Object.entries(counts)) {
    if (count === BLOCK_SIZE) {
      total += BLOCK_PRICE;
    } else {
      total += count * (BASE_PREMIUMS[type] ?? 0);
    }
  }
  return total + PROCESSING_FEE;
};

export const processSteps = (customer: Customer, steps: Array<{ op: string; items: Array<{ type: string }> }>): Array<QuoteResult> =>
  steps.map((step) => ({
    premium: quotePremium(step.items),
  }));

