const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

interface Customer {
  yearsWithMHPCO: number;
}

interface QuoteResult {
  premium: number;
}

const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PRICE = 60;

interface Item {
  type: string;
  enchantment?: number;
  cursed?: boolean;
}

const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;

const basePremiumFor = (type: string): number => BASE_PREMIUMS[type] ?? 0;

const itemSurcharge = (item: Item): number => {
  const base = basePremiumFor(item.type);
  let surcharge = 0;
  if (item.cursed) {
    surcharge += base * CURSED_SURCHARGE_RATE;
  }
  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
    surcharge += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
  }
  return surcharge;
};

const quotePremium = (items: Array<Item>): number => {
  const typeCounts: Record<string, number> = {};
  for (const item of items) {
    typeCounts[item.type] = (typeCounts[item.type] ?? 0) + 1;
  }
  let total = 0;
  for (const [type, count] of Object.entries(typeCounts)) {
    if (count === COMPONENT_BLOCK_SIZE) {
      total += COMPONENT_BLOCK_PRICE;
    } else {
      total += count * basePremiumFor(type);
    }
  }
  for (const item of items) {
    total += itemSurcharge(item);
  }
  return total + PROCESSING_FEE;
};

export const processSteps = (customer: Customer, steps: Array<{ op: string; items: Array<Item> }>): Array<QuoteResult> =>
  steps.map((step) => ({
    premium: quotePremium(step.items),
  }));

